module RefModule(
  input [7:0] data_in,
  input [2:0] shift_amount,
  input shift_direction,
  output [7:0] data_out
);wire [7:0] shifted_data;

  wire __shifted_data_tmp = (shift_direction) ? (data_in << shift_amount) : (data_in >> shift_amount);
  assign shifted_data = __shifted_data_tmp;

  assign data_out = shifted_data;

endmodule
